import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

const transferTaskSchema = z.object({
  taskId: z.string(),
  sourceTeamId: z.string(),
  targetTeamId: z.string(),
});

app.post('/transfer-task', async (c) => {
  const body = await c.req.json();
  const result = transferTaskSchema.safeParse(body);

  if (!result.success) {
    return c.json({ error: 'Invalid request body' }, 400);
  }

  const { taskId, sourceTeamId, targetTeamId } = result.data;

  // Check if the caller is an admin of the source team
  // This is a placeholder for actual authentication and authorization logic
  const isAdminOfSourceTeam = await checkIfUserIsAdmin(c.req.user, sourceTeamId);
  if (!isAdminOfSourceTeam) {
    return c.json({ error: 'You must be an admin of the source team' }, 403);
  }

  // Check if both teams exist
  const sourceTeamExists = await teamExists(sourceTeamId);
  const targetTeamExists = await teamExists(targetTeamId);

  if (!sourceTeamExists || !targetTeamExists) {
    return c.json({ error: 'One or both teams do not exist' }, 404);
  }

  // Transfer the task
  await transferTask(taskId, sourceTeamId, targetTeamId);

  // Emit a task.transferred event
  emitEvent('task.transferred', { taskId, sourceTeamId, targetTeamId });

  return c.json({ message: 'Task transferred successfully' }, 200);
});

